import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-anthropic-key' });
const vex = new Vex({ apiKey: 'your-vex-key' });

const response = await anthropic.messages.create({
  model: 'claude-3-5-sonnet-20240620',
  max_tokens: 1024,
  tools: [
    { name: 'extract_skills', inputSchema: { type: 'object', properties: { resume: { type: 'string' } } } },
    { name: 'match_experience', inputSchema: { type: 'object', properties: { jd: { type: 'string' } } } }
  ],
  messages: [{ role: 'user', content: 'Rank candidate against JD' }]
});

const verification = await vex.verify({
  policy: 'nyc-ll144-bias-check',
  inputs: { resume, jd },
  outputs: response.content,
  metadata: { tools_used: response.tools }
});
if (!verification.passed) {
  console.error('Conflicting tool results flagged');
}
